<template>
  <div style="user-select: none;">
    <a-card style="width: 100%; border-radius: 12px; min-height: 300px; padding: 12px 0;" v-if="form.id">
      <a-row :gutter="16" style="margin: 16px 0px;">
        <a-col class="gutter-row" :span="24">
          <div style="background-color: #eee; padding: 12px 16px; border-radius: 4px;">
            <h2 style="margin-bottom: 0px; text-align: justify;" class="text-bolder">{{ form.voteName }}</h2>
          </div>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]" style="margin: 0px">
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('detailConfig')">
            <p class="button-text text-bolder">评分配置</p>
          </div>
        </a-col>
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;">
            <p class="button-text text-bolder button-text-disabled">管理员</p>
          </div>
        </a-col>
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('scoreRuleList')">
            <p class="button-text text-bolder">评分规则</p>
          </div>
        </a-col>
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('contestantList')">
            <p class="button-text text-bolder">被评人</p>
          </div>
        </a-col>
      </a-row>
      <h3 style="margin: 0px 12px;">评委管理</h3>
      <a-row :gutter="[16, 16]" style="margin: 0px">
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('groupList')">
            <p class="button-text text-bolder">评委分组</p>
          </div>
        </a-col>
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('inviteList')">
            <p class="button-text text-bolder">评委邀请</p>
          </div>
        </a-col>
        <a-col class="gutter-row" :xs="24" :sm="24" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('judgeWhiteList')">
            <p class="button-text text-bolder">评委白名单</p>
          </div>
        </a-col>
      </a-row>
      <h3 style="margin: 0px 12px;">数据与结算</h3>
      <a-row :gutter="[16, 16]" style="margin: 0px">
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;">
            <p class="button-text text-bolder button-text-disabled">结算评分</p>
          </div>
        </a-col>
        <a-col class="gutter-row" :xs="12" :sm="12" :md="8" :lg="6" :xl="4" :xxl="3">
          <div style="background-color: #eee; padding: 10px; border-radius: 4px;" @click="routeByParamVoteId('dataAnalysisList')">
            <p class="button-text text-bolder">数据分析</p>
          </div>
        </a-col>
      </a-row>
    </a-card>
    <span v-else-if="!this.loading">该投票不存在或被隐藏，请 <a @click="$router.push({ name: 'list' })">点此</a> 返回首页</span>
  </div>
</template>
<script>
import { voteBasicConfigurationDetail } from '@/api/voteBasicConfiguration'
export default {
  data() {
    return {
      loading: false,
      form: {
        id: '',
      },
    }
  },
  mounted() {
    this.loadData()
  },
  watch: {
    '$route.params.id'(newId, oldId) {
      if (newId !== oldId) {
        this.loadData(newId)
      }
    },
  },
  methods: {
    loadData() {
      this.loading = true
      this.form = {}
      voteBasicConfigurationDetail({ id: this.$route.params.id }).then(res => {
        if (res) {
          this.form = res
        }
      }).finally(() => {
        this.loading = false
      })
    },
    routeByParamVoteId(routeName) {
      this.$router.push({
        name: routeName,
        params: {
          id: this.$route.params.id,
        },
      })
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 8px !important;
}

.button-text {
  margin-bottom: 0px;
  font-size: 20px;
  color: #000;
  text-align: center;
}

.button-text-disabled {
  color: #999 !important
}

.text-bolder {
  font-weight: 700px;
}

@media only screen and (max-width: 767px) {
  .text-bolder {
    text-shadow: 0.3px 0 0 currentColor, -0.3px 0 0 currentColor, 0 0.3px 0 currentColor, 0 -0.3px 0 currentColor;
  }
}
</style>
